```class Solution {
    public int smallestValue(int n) {
        int res = n;
        while (true) {
            boolean isPrime = true;
            for (int i = 2; i * i <= res; i++) {
                if (res % i == 0) {
                    isPrime = false;
                    res = sumOfFactors(res);
                    break;
                }
            }
            if (isPrime) {
                return res;
            }
        }
    }

    private int sumOfFactors(int n) {
        int sum = 0;
        for (int i = 1; i <= n; i++) {
            if (n % i == 0) {
                sum += i;
            }
        }
        return sum;
    }
}
